import React, { useState, useEffect } from 'react';
import api from '../api/axiosConfig';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';

const EmpleadosList = () => {
  const [empleados, setEmpleados] = useState([]);
  const [mensaje, setMensaje] = useState('');
  const [errorMsg, setErrorMsg] = useState('');

  const [formData, setFormData] = useState({
    nombre: '',
    apellido: '',
    identificacion: '',
    tipo: 'PLAZA_FIJA',
    direccion: '',
    salarioBaseVigente: ''
  });

  const [editandoId, setEditandoId] = useState(null);

  useEffect(() => {
    cargarEmpleados();
  }, []);

  const cargarEmpleados = async () => {
    try {
      const response = await api.get('/empleados');
      setEmpleados(response.data);
    } catch (err) {
      setErrorMsg('No se pudieron recuperar los empleados de la base de datos.');
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMensaje('');
    setErrorMsg('');

    const datosEnviar = {
      ...formData,
      salarioBaseVigente: parseFloat(formData.salarioBaseVigente)
    };

    try {
      if (editandoId) {
        await api.put(`/empleados/${editandoId}`, datosEnviar);
        setMensaje('¡Empleado actualizado con éxito!');
      } else {
        await api.post('/empleados', datosEnviar);
        setMensaje('¡Empleado registrado con éxito!');
      }
      limpiarFormulario();
      cargarEmpleados();
    } catch (err) {
      const backendError = err.response?.data?.message || 'Error en la transacción.';
      setErrorMsg(backendError);
    }
  };

  const handleIniciarEdicion = (emp) => {
    setEditandoId(emp.id_empleado);
    setFormData({
      nombre: emp.nombre,
      apellido: emp.apellido,
      identificacion: emp.identificacion,
      tipo: emp.tipo || 'PLAZA_FIJA',
      direccion: emp.direccion || '',
      salarioBaseVigente: emp.salarioBaseVigente
    });
  };

  const handleEliminar = async (id) => {
    if (window.confirm('¿Confirmas la eliminación de este empleado?')) {
      setMensaje('');
      setErrorMsg('');
      try {
        await api.delete(`/empleados/${id}`);
        setMensaje('Empleado removido del sistema de forma correcta.');
        cargarEmpleados();
      } catch (err) {
        setErrorMsg('Restricción de Integridad: El empleado posee planillas vinculadas en el historial y no puede ser borrado.');
      }
    }
  };

  const limpiarFormulario = () => {
    setEditandoId(null);
    setFormData({ nombre: '', apellido: '', identificacion: '', tipo: 'PLAZA_FIJA', direccion: '', salarioBaseVigente: '' });
  };

  return (
    <div style={{ fontFamily: 'sans-serif', color: '#334155' }}>
      <Navbar />
      <Sidebar />
      
      <main style={{ marginLeft: '260px', marginTop: '80px', padding: '20px' }}>
        <h2>👥 Control e Historial de Personal</h2>
        
        {mensaje && <p style={{ color: '#16a34a', backgroundColor: '#f0fdf4', padding: '10px', borderRadius: '4px', fontWeight: 'bold' }}>{mensaje}</p>}
        {errorMsg && <p style={{ color: '#dc2626', backgroundColor: '#fef2f2', padding: '10px', borderRadius: '4px', fontWeight: 'bold' }}>{errorMsg}</p>}

        <div style={{ border: '1px solid #e2e8f0', padding: '20px', marginBottom: '30px', borderRadius: '8px', backgroundColor: '#ffffff' }}>
          <h3 style={{ marginTop: 0 }}>{editandoId ? '📝 Modificar Parámetros de Empleado' : '➕ Registrar Alta de Empleado'}</h3>
          <form onSubmit={handleSubmit}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '15px' }}>
              <div>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Nombres:</label>
                <input type="text" name="nombre" value={formData.nombre} onChange={handleChange} style={{ width: '94%', padding: '8px', border: '1px solid #cbd5e1', borderRadius: '4px' }} required />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Apellidos:</label>
                <input type="text" name="apellido" value={formData.apellido} onChange={handleChange} style={{ width: '94%', padding: '8px', border: '1px solid #cbd5e1', borderRadius: '4px' }} required />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Identificación (DUI):</label>
                <input type="text" name="identificacion" value={formData.identificacion} onChange={handleChange} style={{ width: '94%', padding: '8px', border: '1px solid #cbd5e1', borderRadius: '4px' }} required />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Modalidad de Contratación:</label>
                <select name="tipo" value={formData.tipo} onChange={handleChange} style={{ width: '100%', padding: '8px', border: '1px solid #cbd5e1', borderRadius: '4px' }}>
                  <option value="PLAZA_FIJA">Plaza Fija (Aplica Descuentos Ley)</option>
                  <option value="SERVICIOS_PROFESIONALES">Servicios Profesionales (Renta Directa)</option>
                </select>
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Salario Nominal ($):</label>
                <input type="number" step="0.01" name="salarioBaseVigente" value={formData.salarioBaseVigente} onChange={handleChange} style={{ width: '94%', padding: '8px', border: '1px solid #cbd5e1', borderRadius: '4px' }} required />
              </div>
              <div>
                <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Dirección de Residencia:</label>
                <input type="text" name="direccion" value={formData.direccion} onChange={handleChange} style={{ width: '94%', padding: '8px', border: '1px solid #cbd5e1', borderRadius: '4px' }} />
              </div>
            </div>
            <button type="submit" style={{ backgroundColor: editandoId ? '#ea580c' : '#2563eb', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '4px', fontWeight: 'bold', cursor: 'pointer' }}>
              {editandoId ? 'Guardar Cambios' : 'Dar de Alta'}
            </button>
            {editandoId && (
              <button type="button" onClick={limpiarFormulario} style={{ marginLeft: '10px', padding: '10px 20px', borderRadius: '4px', border: '1px solid #cbd5e1', cursor: 'pointer' }}>
                Cancelar
              </button>
            )}
          </form>
        </div>

        <h3>Listado General del Personal</h3>
        <table border="1" cellPadding="10" style={{ width: '100%', borderCollapse: 'collapse', backgroundColor: '#ffffff', border: '1px solid #e2e8f0', borderRadius: '6px' }}>
          <thead>
            <tr style={{ backgroundColor: '#f8fafc', color: '#0f172a', textAlign: 'left' }}>
              <th>ID</th>
              <th>Empleado</th>
              <th>DUI / Identificación</th>
              <th>Régimen</th>
              <th>Salario Base</th>
              <th>Acciones de Mantenimiento</th>
            </tr>
          </thead>
          <tbody>
            {empleados.length > 0 ? (
              empleados.map((emp) => (
                <tr key={emp.id_empleado} style={{ borderBottom: '1px solid #e2e8f0' }}>
                  <td><strong>{emp.id_empleado}</strong></td>
                  <td>{emp.nombre} {emp.apellido}</td>
                  <td>{emp.identificacion}</td>
                  <td><span style={{ fontSize: '0.85rem', backgroundColor: '#f1f5f9', padding: '3px 8px', borderRadius: '12px' }}>{emp.tipo}</span></td>
                  <td>${emp.salarioBaseVigente.toFixed(2)}</td>
                  <td>
                    <button onClick={() => handleIniciarEdicion(emp)} style={{ marginRight: '8px', padding: '5px 10px', cursor: 'pointer', borderRadius: '4px', border: '1px solid #cbd5e1', backgroundColor: '#fff' }}>✏️ Editar</button>
                    <button onClick={() => handleEliminar(emp.id_empleado)} style={{ padding: '5px 10px', backgroundColor: '#fee2e2', color: '#ef4444', border: '1px solid #fca5a5', borderRadius: '4px', cursor: 'pointer' }}>🗑️ Borrar</button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6" style={{ textAlign: 'center', color: '#64748b' }}>No existen colaboradores cargados en el sistema relacional.</td>
              </tr>
            )}
          </tbody>
        </table>
      </main>
    </div>
  );
};

export default EmpleadosList;
